// Validate required fields and normalize.
// Returns { valid: bool, error?, ...normalized } so a downstream IF can branch
// to a 400-Respond instead of throwing (which would just silently 200-empty
// the webhook caller).
const body = $input.item.json.body || $input.item.json;
const { name, email, company } = body;

if (!name || !email || !company) {
  return { json: { valid: false, error: 'Missing required fields: name, email, company' } };
}

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  return { json: { valid: false, error: `Invalid email: ${email}` } };
}

const domain = email.split('@')[1].toLowerCase();

return {
  json: {
    valid: true,
    name: name.trim(),
    email: email.toLowerCase().trim(),
    company: company.trim(),
    domain,
    receivedAt: new Date().toISOString()
  }
};

// Map the mock Clearbit-compatible payload back onto the normalized lead shape.
// The mock API returns Clearbit-like fields so this mapper is the same boundary
// we would keep if the HTTP node were pointed at the real Clearbit endpoint.
const lead = $('Validate & Normalize').item.json;
const clearbit = $input.item.json || {};

const hasCompany = clearbit.found !== false && Boolean(clearbit.metrics || clearbit.category || clearbit.name || clearbit.domain);

function employeesFromRange(range) {
  const ranges = {
    '1-10': 10,
    '11-50': 50,
    '51-250': 250,
    '251-1K': 1000,
    '1K-5K': 5000,
    '5K-10K': 10000,
    '10K-50K': 50000,
    '50K-100K': 100000,
    '100K+': 100000
  };
  return ranges[range] || 0;
}

const employees = hasCompany
  ? (Number(clearbit.metrics?.employees ?? 0) || employeesFromRange(clearbit.metrics?.employeesRange) || 0)
  : 0;
const category = hasCompany ? (clearbit.category || {}) : {};
const rawIndustry = category.industry || category.industryGroup || category.sector || 'Unknown';

const signals = [
  category.sector,
  category.industryGroup,
  category.industry,
  ...(Array.isArray(clearbit.tags) ? clearbit.tags : []),
  ...(Array.isArray(clearbit.techCategories) ? clearbit.techCategories : [])
].filter(Boolean).join(' ').toLowerCase();

let industry = rawIndustry;
if (/tech|software|internet|saas|cloud|data|security|developer|computer|information technology/.test(signals)) {
  industry = 'Tech';
} else if (/finance|bank|insurance|financial/.test(signals)) {
  industry = 'Finance';
} else if (/health|medical|biotech|pharma/.test(signals)) {
  industry = 'Healthcare';
} else if (/retail|commerce|consumer|food/.test(signals)) {
  industry = rawIndustry === 'Food' ? 'Food' : 'Retail';
}

return {
  json: {
    ...lead,
    clearbit: hasCompany ? {
      id: clearbit.id,
      name: clearbit.name,
      domain: clearbit.domain,
      employeesRange: clearbit.metrics?.employeesRange,
      rawIndustry,
      mock: clearbit.mock === true
    } : {
      error: clearbit.error || clearbit.message || 'No mock company match'
    },
    enrichment: {
      companySize: employees,
      industry: hasCompany ? industry : 'Unknown',
      source: hasCompany ? (clearbit.mockSource || 'mock_api') : 'mock_api_unavailable'
    }
  }
};

// Lead scoring per spec:
//   Company size: 1-50 = 1pt, 51-500 = 3pt, 500+ = 5pt
//   Industry:     Tech = 3pt,  others = 1pt
//   High tier: >=6, Medium: 3-5, Low: < 3

const { companySize, industry } = $input.item.json.enrichment;

let sizePoints;
if (companySize <= 50)       sizePoints = 1;
else if (companySize <= 500) sizePoints = 3;
else                         sizePoints = 5;

const industryPoints = industry === 'Tech' ? 3 : 1;
const total = sizePoints + industryPoints;

let tier;
if (total >= 6)      tier = 'high';
else if (total >= 3) tier = 'medium';
else                 tier = 'low';

return {
  json: {
    ...$input.item.json,
    score: { sizePoints, industryPoints, total, tier }
  }
};

const i = $input.item.json;
return { json: {
  email: i.email,
  receivedAt: i.receivedAt,
  name: i.name,
  company: i.company,
  domain: i.domain,
  companySize: i.enrichment.companySize,
  industry: i.enrichment.industry,
  score: i.score.total,
  tier: i.score.tier
}};

